  `script_id` int(11) NOT NULL AUTO_INCREMENT COMMENT '脚本ID',
  `script_name` varchar(100) NOT NULL COMMENT '脚本名称',
  `script_desc` varchar(500) DEFAULT NULL COMMENT '脚本描述',
  `target_package` varchar(100) NOT NULL COMMENT '目标APP包名',
  `config` text NOT NULL COMMENT '脚本配置JSON',
  `version` varchar(20) DEFAULT '1.0.0' COMMENT '版本号',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态：0草稿 1上线 2下线',
  `priority` tinyint(1) DEFAULT '2' COMMENT '优先级：1高 2中 3低',
  `execution_frequency` varchar(20) DEFAULT 'once' COMMENT '执行频次',
  `timeout` int(11) DEFAULT '300' COMMENT '超时时间(秒)',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`script_id`),
  KEY `idx_status` (`status`),
  KEY `idx_package` (`target_package`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COMMENT='脚本表';
