--
-- Table structure for table `auto_user`
--

DROP TABLE IF EXISTS `auto_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `auto_user` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `username` varchar(50) NOT NULL COMMENT '用户名',
  `password` varchar(64) NOT NULL COMMENT '密码(SHA256)',
  `salt` varchar(32) NOT NULL COMMENT '盐值',
  `device_id` varchar(64) DEFAULT NULL COMMENT '绑定设备ID',
  `expire_time` datetime DEFAULT NULL COMMENT '账号有效期',
  `referrer_id` int(11) DEFAULT NULL COMMENT '推荐人ID',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态：1启用 0禁用',
  `role` tinyint(1) DEFAULT '1' COMMENT '角色：1普通 2VIP 9管理员',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `uk_username` (`username`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_status` (`status`),
  KEY `idx_referrer_id` (`referrer_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COMMENT='用户表';
/*!40101 SET character_set_client = @saved_cs_client */;

